svg.script:

(function() {

  var DEFAULT_TITLE = "zodiac";

  function applySettings() {
    try {
      var savedTitle = localStorage.getItem("z_title");
      var savedIcon = localStorage.getItem("z_icon");
      var savedLeave = localStorage.getItem("z_leave");

      document.title = savedTitle && savedTitle.trim()
        ? savedTitle
        : DEFAULT_TITLE;

      var icon = document.querySelector("link[rel='icon']");
      if (!icon) {
        icon = document.createElement("link");
        icon.rel = "icon";
        document.head.appendChild(icon);
      }
      if (savedIcon && savedIcon.trim()) {
        icon.href = savedIcon;
      }

      window.onbeforeunload = savedLeave === "true" ? function(){ return true; } : null;

    } catch(e) {}
  }

  applySettings();

  window.addEventListener("storage", function(e) {
    if (e.key === "z_title") {
      document.title = e.newValue && e.newValue.trim()
        ? e.newValue
        : DEFAULT_TITLE;
    }

    if (e.key === "z_icon") {
      var icon = document.querySelector("link[rel='icon']");
      if (!icon) {
        icon = document.createElement("link");
        icon.rel = "icon";
        document.head.appendChild(icon);
      }
      if (e.newValue && e.newValue.trim()) {
        icon.href = e.newValue;
      }
    }

    if (e.key === "z_leave") {
      window.onbeforeunload = e.newValue === "true"
        ? function(){ return true; }
        : null;
    }
  });


  var URLS = [
    "https://raw.githack.com/darkdragonzxs/zd-pages/main/zodiac.html",
    "https://raw.githubusercontent.com/darkdragonzxs/zd-pages/main/zodiac.html",
    "https://cdn.statically.io/gh/darkdragonzxs/zd-pages@main/zodiac.html",
    "https://cdn.jsdelivr.net/gh/Darkdragonzxs/zd-pages@latest/zodiac.html"
  ];

  var frame = document.getElementById("f");

  function tryFetch(i) {
    if (i >= URLS.length) return;

    fetch(URLS[i])
      .then(function(r) {
        if (!r.ok) throw new Error();
        return r.text();
      })
      .then(function(html) {
        var blob = new Blob([html], { type: "text/html" });
        frame.src = URL.createObjectURL(blob);
      })
      .catch(function() {
        tryFetch(i + 1);
      });
  }

  tryFetch(0);

}());
